<script setup>
import { ref, watch } from 'vue';
import { useRoute } from 'vue-router';
import { useDarkMode } from './src/useDarkMode.js';
import { settingsConfig } from './src/settings-config.js';
import { useSettingsData } from './src/useSettingsData.js';
import { useSettingsSearch } from './src/useSettingsSearch.js';
import { useSettingsUrl } from './src/useSettingsUrl.js';
import { useThemeScales } from './src/useThemeScales.js';
import { useLicense } from './src/useLicense.js';
import Notifications from '@/components/utility/notifications/index.vue';
import AppIcon from '@/components/utility/icons/index.vue';
import AppButton from '@/components/utility/app-button/index.vue';
import SettingsPanel from './src/settings-panel.vue';
import Drawer from '@/components/utility/drawer/index.vue';

const route = useRoute();
const { isDark } = useDarkMode();
const selectedCategory = ref('general');
const drawer = ref(null);
const searchQuery = ref('');

const settingsCategories = [
  {
    value: 'general',
    label: __('General', 'uixpress'),
    icon: 'settings',
    description: __('Core plugin settings and license management', 'uixpress'),
  },
  {
    value: 'login',
    label: __('Login', 'uixpress'),
    icon: 'login',
    description: __('Customize login page appearance and security', 'uixpress'),
  },
  {
    value: 'theme',
    label: __('Theme', 'uixpress'),
    icon: 'palette',
    description: __('Colors, styling, and visual customization', 'uixpress'),
  },
  {
    value: 'whitelabel',
    label: __('White Label', 'uixpress'),
    icon: 'diamond_shine',
    description: __(
      'Rebrand and customize interface text and icons',
      'uixpress'
    ),
  },
  {
    value: 'menu',
    label: __('Menu', 'uixpress'),
    icon: 'menu',
    description: __('Admin menu behavior and interaction settings', 'uixpress'),
  },
  {
    value: 'posts',
    label: __('Posts', 'uixpress'),
    icon: 'article',
    description: __('Post management and display preferences', 'uixpress'),
  },
  {
    value: 'plugins',
    label: __('Plugins', 'uixpress'),
    icon: 'extension',
    description: __('Plugin management interface options', 'uixpress'),
  },
  {
    value: 'dashboard',
    label: __('Dashboard', 'uixpress'),
    icon: 'dashboard',
    description: __(
      'Custom dashboard and admin interface settings',
      'uixpress'
    ),
  },
  {
    value: 'analytics',
    label: __('Analytics', 'uixpress'),
    icon: 'analytics',
    description: __('Built-in analytics and tracking settings', 'uixpress'),
  },
  {
    value: 'media',
    label: __('Media', 'uixpress'),
    icon: 'image',
    description: __('Media library and upload management settings', 'uixpress'),
  },
  {
    value: 'users',
    label: __('Users', 'uixpress'),
    icon: 'people',
    description: __('User management and administration settings', 'uixpress'),
  },
  {
    value: 'comments',
    label: __('Comments', 'uixpress'),
    icon: 'comment',
    description: __(
      'Comment management and administration settings',
      'uixpress'
    ),
  },
  {
    value: 'security',
    label: __('Security', 'uixpress'),
    icon: 'security',
    description: __('Security settings and administration', 'uixpress'),
  },
  {
    value: 'database',
    label: __('Database', 'uixpress'),
    icon: 'database',
    description: __('Database explorer and management settings', 'uixpress'),
  },
];

const {
  loading,
  saving,
  settingsFetched,
  settingsUploader,
  settings: uixpress_settings,
  loadSettings,
  saveSettings,
  exportSettings,
  handleSettingsFileUpload,
} = useSettingsData();

const { filteredCategories } = useSettingsSearch({
  searchQuery,
  settingsConfig,
  settingsCategories,
});

useSettingsUrl({
  route,
  selectedCategory,
  settingsCategories,
});

useThemeScales({
  settings: uixpress_settings,
  settingsFetched,
});

const { keyactions, activateLicenseKey, validateLicence, removeKey } = useLicense({
  settings: uixpress_settings,
  saveSettings,
});

const handleActivateLicense = async (key) => {
  await activateLicenseKey(key);
};

const handleRemoveLicense = async () => {
  await removeKey();
};

watch(
  () => uixpress_settings.value,
  () => {
    if (!settingsFetched.value) return;
    const settingsUpdateEvent = new CustomEvent('uipx-settings-update', {
      detail: uixpress_settings.value,
    });
    document.dispatchEvent(settingsUpdateEvent);
  },
  { deep: true }
);

loadSettings().then((loaded) => {
  if (loaded) {
    validateLicence();
  }
});
</script>

<template>
  <component is="style">html{font-size:14px;}#wpcontent{padding:0}</component>
  <div class="uixpress-isolation">
    <Notifications />

    <div
      class="flex h-screen bg-zinc-50 dark:bg-zinc-950 text-zinc-900 dark:text-zinc-100 font-sans uipx-normalize max-h-[var(--uixp-body-height)] overflow-hidden gap-3 p-[1.5px]"
      :class="isDark ? 'dark' : ''"
    >
      <!-- Left Sidebar -->
      <div
        class="md:w-96 w-full flex flex-col bg-white dark:bg-zinc-800/30 rounded-2xl border border-zinc-200 dark:border-zinc-700/20 overflow-hidden max-h-full"
      >
        <!-- Header -->
        <div class="p-6">
          <div class="flex items-center gap-4 mb-4">
            <h1 class="text-xl font-medium grow">
              {{ __('Settings', 'uixpress') }}
            </h1>
            <div class="flex items-center">
              <AppButton
                type="transparent"
                @click="exportSettings"
                class="text-sm"
              >
                <AppIcon icon="download" class="text-xl" />
              </AppButton>
              <AppButton
                type="transparent"
                @click="settingsUploader.click()"
                class="text-sm"
              >
                <AppIcon icon="upload" class="text-xl" />
                <input
                  type="file"
                  accept=".json"
                  @change="handleSettingsFileUpload"
                  class="hidden"
                  ref="settingsUploader"
                />
              </AppButton>
            </div>
          </div>

          <!-- Search Input -->
          <div class="relative mb-4">
            <div
              class="absolute top-0 left-0 h-full flex items-center px-3 pointer-events-none"
            >
              <AppIcon icon="search" class="text-zinc-400 text-sm" />
            </div>
            <input
              v-model="searchQuery"
              type="text"
              :placeholder="__('Search settings...', 'uixpress')"
              class="w-full pl-9 pr-3 py-2.5 text-sm border border-zinc-200 dark:border-zinc-700/40 rounded-xl bg-zinc-50 dark:bg-zinc-800/50 text-zinc-900 dark:text-zinc-100 placeholder-zinc-400 dark:placeholder-zinc-500 transition-all outline outline-transparent outline-offset-[-2px] focus:outline-indigo-300 dark:focus:outline-indigo-700 focus:shadow-xs focus:bg-white dark:focus:bg-zinc-800"
            />
            <button
              v-if="searchQuery"
              @click="searchQuery = ''"
              class="absolute top-0 right-0 h-full flex items-center px-3 text-zinc-400 hover:text-zinc-600 dark:hover:text-zinc-300 transition-colors"
            >
              <AppIcon icon="close" class="text-sm" />
            </button>
          </div>
        </div>

        <!-- Categories List -->
        <div class="flex-1 overflow-auto">
          <div
            v-if="loading && !settingsCategories.length"
            class="p-8 text-center"
          >
            <div
              class="w-12 h-12 bg-zinc-100 dark:bg-zinc-800 rounded-full flex items-center justify-center mx-auto mb-3"
            >
              <AppIcon
                icon="settings"
                class="text-zinc-400 text-xl animate-pulse"
              />
            </div>
            <p class="text-sm text-zinc-500">
              {{ __('Loading settings...', 'uixpress') }}
            </p>
          </div>

          <div v-else class="py-2 px-6 flex flex-col gap-1">
            <!-- No Results Message -->
            <div
              v-if="filteredCategories.length === 0"
              class="py-8 text-center"
            >
              <div
                class="w-12 h-12 bg-zinc-100 dark:bg-zinc-800 rounded-full flex items-center justify-center mx-auto mb-3"
              >
                <AppIcon icon="search" class="text-zinc-400 text-xl" />
              </div>
              <p class="text-sm text-zinc-500 dark:text-zinc-400">
                {{ __('No settings found', 'uixpress') }}
              </p>
              <p class="text-xs text-zinc-400 dark:text-zinc-500 mt-1">
                {{ __('Try a different search term', 'uixpress') }}
              </p>
            </div>

            <!-- Categories List -->
            <div
              v-for="category in filteredCategories"
              :key="category.value"
              @click="
                selectedCategory = category.value;
                drawer = true;
              "
              class="flex items-center gap-3 px-3 py-3 cursor-pointer transition-colors hover:bg-zinc-100 dark:hover:bg-zinc-800 rounded-xl transition-all cursor-pointer group"
              :class="
                selectedCategory === category.value
                  ? 'bg-zinc-100 dark:bg-zinc-800/60'
                  : ''
              "
            >
              <!-- Category Icon -->
              <div class="flex-shrink-0">
                <div
                  class="w-8 h-8 rounded-lg flex items-center justify-center"
                  :class="
                    selectedCategory === category.value
                      ? 'bg-indigo-100 dark:bg-indigo-900/50 text-indigo-600 dark:text-indigo-400'
                      : 'bg-zinc-100 dark:bg-zinc-800 text-zinc-500 dark:text-zinc-400'
                  "
                >
                  <AppIcon :icon="category.icon" class="text-sm" />
                </div>
              </div>

              <!-- Category Info -->
              <div class="flex-1 min-w-0">
                <div class="flex items-center gap-2 mb-0.5">
                  <span
                    class="font-medium text-sm truncate"
                    :class="
                      selectedCategory === category.value
                        ? 'text-zinc-900 dark:text-white'
                        : 'text-zinc-500 dark:text-zinc-400'
                    "
                  >
                    {{ category.label }}
                  </span>
                  <span
                    v-if="category.hasMatchingSettings && category.matchCount"
                    class="px-1.5 py-0.5 text-xs font-medium rounded-full bg-indigo-100 dark:bg-indigo-900/50 text-indigo-600 dark:text-indigo-400"
                  >
                    {{ category.matchCount }}
                  </span>
                </div>
                <div class="text-xs text-zinc-500 dark:text-zinc-400 truncate">
                  {{ category.description }}
                </div>
              </div>

              <!-- Arrow indicator -->
              <div
                class="flex-shrink-0 opacity-0 group-hover:opacity-100 transition-opacity"
              >
                <AppIcon icon="chevron_right" class="text-zinc-400 text-sm" />
              </div>
            </div>
          </div>
        </div>
      </div>

      <!-- Right Content Area -->
      <div
        class="flex-1 flex flex-col bg-white dark:bg-zinc-800/30 rounded-l-2xl border border-zinc-200 dark:border-zinc-700/20"
      >
        <!-- Loading State - show until we have valid settings (prevents form fields emitting defaults) -->
        <div v-if="loading || !settingsFetched" class="flex-1 flex items-center justify-center">
          <div class="text-center">
            <div
              class="w-16 h-16 bg-zinc-100 dark:bg-zinc-800 rounded-2xl flex items-center justify-center mx-auto mb-4"
            >
              <AppIcon
                icon="settings"
                class="text-2xl text-zinc-400 animate-pulse"
              />
            </div>
            <h3
              class="text-lg font-medium text-zinc-900 dark:text-zinc-100 mb-2"
            >
              {{ __('Loading Settings...', 'uixpress') }}
            </h3>
          </div>
        </div>

        <!-- Empty State -->
        <div
          v-else-if="!selectedCategory"
          class="flex-1 flex items-center justify-center"
        >
          <div class="text-center">
            <div
              class="w-16 h-16 bg-zinc-100 dark:bg-zinc-800 rounded-2xl flex items-center justify-center mx-auto mb-4"
            >
              <AppIcon icon="settings" class="text-2xl text-zinc-400" />
            </div>
            <h3
              class="text-lg font-medium text-zinc-900 dark:text-zinc-100 mb-2"
            >
              {{ __('Settings Panel', 'uixpress') }}
            </h3>
            <p class="text-sm text-zinc-500 mb-4">
              {{
                __(
                  'Select a category from the list to configure your settings.',
                  'uixpress'
                )
              }}
            </p>
          </div>
        </div>

        <!-- Settings Panel -->
        <div
          v-else
          class="flex-1 flex flex-col hidden md:flex max-h-full overflow-y-auto"
        >
          <SettingsPanel
            v-model="uixpress_settings"
            :tab="selectedCategory"
            :saving="saving"
            :settings-ready="settingsFetched"
            :keyactions="keyactions"
            :on-activate-license="handleActivateLicense"
            :on-remove-license="handleRemoveLicense"
            :categories="settingsCategories"
            :searchQuery="searchQuery"
            @save="saveSettings"
          />
        </div>

        <!-- Mobile Drawer -->
        <Drawer v-model="drawer" class="md:hidden" :showHeader="false">
          <SettingsPanel
            v-model="uixpress_settings"
            :tab="selectedCategory"
            :saving="saving"
            :settings-ready="settingsFetched"
            :keyactions="keyactions"
            :on-activate-license="handleActivateLicense"
            :on-remove-license="handleRemoveLicense"
            :categories="settingsCategories"
            :searchQuery="searchQuery"
            @save="saveSettings"
          />
        </Drawer>
      </div>
    </div>
  </div>
</template>

<style>
#wpbody,
#wpcontent {
  padding: 0 !important;
}

html {
  --uixp-body-height: calc(100vh - var(--uixp-toolbar-height) - 1rem);
}
</style>
