<script setup>
import { computed, onMounted, ref, watch } from 'vue';
import AppIcon from '@/components/utility/icons/index.vue';
import { applyFilters } from '@/assets/js/functions/HooksSystem.js';
import '@/pages/dashboard/src/register-categories.js';

const props = defineProps({
  setting: {
    type: Object,
    required: true,
  },
  modelValue: {
    type: Object,
    required: true,
  },
});

const emit = defineEmits(['update:modelValue']);
const categories = ref([]);
const loading = ref(false);

const getDefaultCategories = () => {
  const defaults = [{ value: 'site', label: __('Overview', 'uixpress') }];

  if (props.modelValue?.enable_uixpress_analytics) {
    defaults.push({ value: 'analytics', label: __('Analytics', 'uixpress') });
  }

  return defaults;
};

const loadCategories = async () => {
  loading.value = true;

  try {
    // Match dashboard behavior so third-party integrations can register categories.
    document.dispatchEvent(new CustomEvent('uixpress/dashboard/ready'));
    const filtered = await applyFilters('uixpress/dashboard/categories/register', []);
    categories.value = Array.isArray(filtered) && filtered.length
      ? filtered
      : getDefaultCategories();
  } catch (error) {
    categories.value = getDefaultCategories();
  } finally {
    loading.value = false;
  }
};

const currentOrder = computed(() => {
  const saved = Array.isArray(props.modelValue?.dashboard_tab_order)
    ? props.modelValue.dashboard_tab_order
    : [];

  const availableValues = categories.value.map((category) => category.value);
  const savedInUse = saved.filter((value) => availableValues.includes(value));
  const missing = availableValues.filter((value) => !savedInUse.includes(value));
  const normalizedOrder = [...savedInUse, ...missing];

  return normalizedOrder
    .map((value) => categories.value.find((category) => category.value === value))
    .filter(Boolean);
});

const updateOrder = (nextOrderValues) => {
  emit('update:modelValue', {
    ...props.modelValue,
    dashboard_tab_order: nextOrderValues,
  });
};

const moveCategory = (index, direction) => {
  const items = [...currentOrder.value];
  const targetIndex = index + direction;

  if (targetIndex < 0 || targetIndex >= items.length) return;

  const [moved] = items.splice(index, 1);
  items.splice(targetIndex, 0, moved);
  updateOrder(items.map((item) => item.value));
};

const resetOrder = () => {
  emit('update:modelValue', {
    ...props.modelValue,
    dashboard_tab_order: [],
  });
};

watch(
  () => props.modelValue?.enable_uixpress_analytics,
  () => {
    loadCategories();
  }
);

onMounted(() => {
  loadCategories();
});
</script>

<template>
  <div class="col-span-2 space-y-3">
    <div
      v-if="loading"
      class="text-sm text-zinc-500 dark:text-zinc-400 px-3 py-2 rounded-lg bg-zinc-100 dark:bg-zinc-800/40"
    >
      {{ __('Loading dashboard tabs...', 'uixpress') }}
    </div>

    <template v-else>
      <div
        v-for="(category, index) in currentOrder"
        :key="category.value"
        class="flex items-center gap-3 px-3 py-2.5 rounded-lg border border-zinc-200 dark:border-zinc-700/50 bg-zinc-50 dark:bg-zinc-800/30"
      >
        <AppIcon icon="drag_indicator" class="text-zinc-400 text-base" />

        <span class="flex-1 text-sm text-zinc-700 dark:text-zinc-200">
          {{ category.label }}
        </span>

        <div class="flex items-center gap-1">
          <button
            type="button"
            class="h-8 w-8 inline-flex items-center justify-center rounded-md text-zinc-500 hover:text-zinc-900 dark:text-zinc-400 dark:hover:text-zinc-100 hover:bg-zinc-200 dark:hover:bg-zinc-700 disabled:opacity-40 disabled:cursor-not-allowed"
            :disabled="index === 0"
            @click="moveCategory(index, -1)"
          >
            <AppIcon icon="expand_less" class="text-base" />
          </button>
          <button
            type="button"
            class="h-8 w-8 inline-flex items-center justify-center rounded-md text-zinc-500 hover:text-zinc-900 dark:text-zinc-400 dark:hover:text-zinc-100 hover:bg-zinc-200 dark:hover:bg-zinc-700 disabled:opacity-40 disabled:cursor-not-allowed"
            :disabled="index === currentOrder.length - 1"
            @click="moveCategory(index, 1)"
          >
            <AppIcon icon="expand_more" class="text-base" />
          </button>
        </div>
      </div>

      <div class="flex justify-end pt-1">
        <button
          type="button"
          class="text-xs text-zinc-500 dark:text-zinc-400 hover:text-zinc-900 dark:hover:text-zinc-100 underline decoration-zinc-300 dark:decoration-zinc-600"
          @click="resetOrder"
        >
          {{ __('Reset tab order', 'uixpress') }}
        </button>
      </div>
    </template>
  </div>
</template>
