import { computed, ref } from 'vue';
import { useAppStore } from '@/store/app/app.js';
import { notify } from '@/assets/js/functions/notify.js';
import { isNonProduction } from '@/assets/js/functions/isNonProduction.js';

export const useLicense = ({ settings, saveSettings }) => {
  const appStore = useAppStore();
  const keyactions = ref(false);

  const isActivated = computed(() => {
    if (isNonProduction()) return true;
    return Boolean(settings.value?.license_key && settings.value?.instance_id);
  });

  const activateLicenseKey = async (key) => {
    const cleanKey = key?.trim();
    if (!cleanKey) return false;

    appStore.updateState('loading', true);
    keyactions.value = true;

    try {
      const payload = {
        data: {
          license_key: cleanKey,
          instance_id: window.location.hostname,
        },
      };

      const response = await fetch(
        'https://accounts.uipress.co/api/v1/keys/validate-activate',
        {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify(payload),
        }
      );

      if (!response.ok) {
        const errorData = await response.json().catch(() => ({}));
        notify({
          title: errorData.message || __('Failed to activate key', 'uixpress'),
          type: 'error',
        });
        return false;
      }

      const result = await response.json();
      if (result.error) {
        notify({
          title: result.message || __('Failed to activate key', 'uixpress'),
          type: 'error',
        });
        return false;
      }

      settings.value.license_key = cleanKey;
      settings.value.instance_id = result.activation_id;

      const saved = await saveSettings();
      if (!saved) return false;

      notify({
        title: result.existing
          ? __('Key already activated for this site', 'uixpress')
          : __('Key successfully activated', 'uixpress'),
        type: 'success',
      });

      return true;
    } catch (error) {
      notify({
        title: __('Network error during activation', 'uixpress'),
        type: 'error',
      });
      return false;
    } finally {
      appStore.updateState('loading', false);
      keyactions.value = false;
    }
  };

  const validateLicence = async () => {
    if (!settings.value?.license_key || !settings.value?.instance_id) return;
    if (settings.value.license_key.startsWith('UIXP-')) return;

    const payload = {
      data: {
        license_key: settings.value.license_key,
        instance_id: settings.value.instance_id,
      },
    };

    try {
      const response = await fetch(
        'https://accounts.uipress.co/api/v1/keys/validate-activate',
        {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify(payload),
        }
      );
      if (!response.ok) return;

      const result = await response.json();
      if (result.error) return;
      if (
        result.activation_id &&
        result.activation_id !== settings.value.instance_id
      ) {
        settings.value.instance_id = result.activation_id;
        await saveSettings();
      }
    } catch (_) {}
  };

  const removeKey = async () => {
    appStore.updateState('loading', true);
    keyactions.value = true;

    try {
      if (settings.value.license_key?.startsWith('UIXP-')) {
        settings.value.license_key = '';
        settings.value.instance_id = '';
        const saved = await saveSettings();
        if (saved) {
          notify({ title: __('Instance removed', 'uixpress'), type: 'success' });
        }
        return saved;
      }

      const payload = {
        data: {
          license_key: settings.value.license_key,
          instance_id: settings.value.instance_id,
        },
      };

      const response = await fetch(
        'https://accounts.uipress.co/api/v1/keys/remove-activation',
        {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify(payload),
        }
      );

      // Clear local key either way, then persist.
      settings.value.license_key = '';
      settings.value.instance_id = '';
      const saved = await saveSettings();

      if (!response.ok) {
        const errorData = await response.json().catch(() => ({}));
        notify({
          title: errorData.message || __('Failed to remove activation', 'uixpress'),
          type: 'error',
        });
        return saved;
      }

      const result = await response.json();
      if (result.error) {
        notify({
          title: result.message || __('Failed to remove activation', 'uixpress'),
          type: 'error',
        });
      } else {
        notify({ title: __('Instance removed', 'uixpress'), type: 'success' });
      }

      return saved;
    } catch (error) {
      settings.value.license_key = '';
      settings.value.instance_id = '';
      await saveSettings();
      notify({
        title: __('Network error during removal', 'uixpress'),
        type: 'error',
      });
      return false;
    } finally {
      appStore.updateState('loading', false);
      keyactions.value = false;
    }
  };

  return {
    keyactions,
    isActivated,
    activateLicenseKey,
    validateLicence,
    removeKey,
  };
};
